// Extract email data and PDF attachments
const input = $input.first().json;

// Get email body
const body = input.body?.plain || input.body?.html || input.plain || input.html || input.text || input.Text || input.body || '';
const from = input.from || input.From || input.envelope?.from || '';
const subject = input.subject || input.Subject || '';

// Get attachments (PDF)
let pdfBase64 = null;
let pdfFilename = null;

// Check for attachments in various formats
const attachments = input.attachments || input.Attachments || [];

for (const att of attachments) {
  const filename = att.filename || att.name || att.fileName || '';
  const contentType = att.contentType || att.type || att.mimeType || '';

  if (filename.toLowerCase().endsWith('.pdf') || contentType.includes('pdf')) {
    pdfBase64 = att.content || att.data || att.base64 || null;
    pdfFilename = filename;
    break;
  }
}

// Also check binary data from webhook
const binary = $input.first().binary;
if (!pdfBase64 && binary) {
  for (const key of Object.keys(binary)) {
    const binaryData = binary[key];
    if (binaryData.mimeType?.includes('pdf') || binaryData.fileName?.endsWith('.pdf')) {
      pdfBase64 = binaryData.data;
      pdfFilename = binaryData.fileName;
      break;
    }
  }
}

return [{
  json: {
    body,
    from,
    subject,
    hasPdf: !!pdfBase64,
    pdfFilename,
    pdfBase64
  }
}];

