const aiResponse = $input.first().json;

// Parse the AI response from Claude API
let trips = [];
try {
  // Claude API returns: { content: [{ type: 'text', text: '...' }] }
  let content = '';

  if (aiResponse.content && Array.isArray(aiResponse.content)) {
    // Find the text content block
    const textBlock = aiResponse.content.find(c => c.type === 'text');
    content = textBlock?.text || '';
  } else if (typeof aiResponse.content === 'string') {
    content = aiResponse.content;
  } else if (aiResponse.message?.content) {
    content = aiResponse.message.content;
  } else if (aiResponse.text) {
    content = aiResponse.text;
  }

  // Remove markdown code blocks if present
  content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  // Parse JSON
  trips = JSON.parse(content);

  if (!Array.isArray(trips)) {
    trips = [trips];
  }

  // Validate and clean up each trip
  trips = trips.map(t => ({
    tbrTripId: t.tbrTripId || 'UNKNOWN',
    status: t.status || 'Confirmed',
    passengerName: t.passengerName || 'Unknown',
    passengerPhone: t.passengerPhone || null,
    passengerEmail: t.passengerEmail || null,
    passengerCount: t.passengerCount || 1,
    pickupDatetime: t.pickupDatetime,
    pickupAddress: t.pickupAddress || '',
    dropoffAddress: t.dropoffAddress || '',
    vehicleType: t.vehicleType || 'Sedan',
    flightNumber: t.flightNumber || null,
    notes: t.notes || null,
    fareAmount: typeof t.fareAmount === 'number' ? t.fareAmount : null
  }));

} catch (e) {
  console.log('Failed to parse AI response:', e.message);
  console.log('Raw response:', JSON.stringify(aiResponse).substring(0, 500));
  trips = [];
}

console.log(`Extracted ${trips.length} trips from TBR email`);

return [{ 
  json: { 
    trips,
    source: 'tbr-email',
    extractedAt: new Date().toISOString()
  } 
}];

